#include<bits/stdc++.h>
using namespace std;
const int N = 1e5+5;
const int mod = 1e8-3;
int n,a[N],b[N],ta[N],tb[N],tmp[N];
map<int,int> ma,mb,mp;
int solve(int l,int r){
	if(l==r)return 0;
	int mid=(l+r)/2;
	int as=(solve(l,mid)+solve(mid+1,r))%mod;
	int p1=l,p2=mid+1,cnt=l-1;
	while(p1<=mid&&p2<=r){
		if(a[p2]<a[p1])as=(as+mid-p1+1)%mod,tmp[++cnt]=a[p2++];
		else tmp[++cnt]=a[p1++];
	}
	while(p1<=mid)tmp[++cnt]=a[p1++];
	while(p2<=r)tmp[++cnt]=a[p2++];
	for(int i=l;i<=r;i++)a[i]=tmp[i];
	return as;
}
int main(){
	//freopen("match.in","r",stdin);
	//freopen("match.out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i];ta[i]=a[i];
	}
	for(int i=1;i<=n;i++){
		cin>>b[i];tb[i]=b[i];
	}
	sort(ta+1,ta+n+1);
	sort(tb+1,tb+n+1);
	for(int i=1;i<=n;i++)ma[ta[i]]=i,mb[tb[i]]=i;
	for(int i=1;i<=n;i++)a[i]=ma[a[i]],b[i]=mb[b[i]];
	for(int i=1;i<=n;i++)mp[b[i]]=i;
	for(int i=1;i<=n;i++)a[i]=mp[a[i]];
	cout<<solve(1,n);
	return 0;
}
